import React, { useState, useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { Save } from 'lucide-react';
import { getOrden, createOrden, updateOrden, getClientes } from '../../services/api';
import Loading from '../common/Loading';

export default function OrdenForm() {
  const { id } = useParams();
  const navigate = useNavigate();
  const isEdit = !!id;
  const [loading, setLoading] = useState(isEdit);
  const [saving, setSaving] = useState(false);
  const [clientes, setClientes] = useState([]);

  const [form, setForm] = useState({
    cliente_id: '', origen: 'Manual', material: '', color_tipo: '', espesor: '',
    bacha: '', anafe: '', sena_recibida: 0, saldo_pendiente: 0,
    fecha_entrega: '', prioridad: 'Normal', observaciones: '',
  });

  useEffect(() => {
    getClientes().then((res) => setClientes(res.data));
    if (id) {
      getOrden(id).then((res) => {
        const d = res.data;
        setForm({
          cliente_id: d.cliente_id || '',
          origen: d.origen || 'Manual',
          material: d.material || '', color_tipo: d.color_tipo || '', espesor: d.espesor || '',
          bacha: d.bacha || '', anafe: d.anafe || '',
          sena_recibida: d.sena_recibida || 0, saldo_pendiente: d.saldo_pendiente || 0,
          fecha_entrega: d.fecha_entrega ? d.fecha_entrega.slice(0, 10) : '',
          prioridad: d.prioridad || 'Normal',
          observaciones: d.observaciones || '',
        });
        setLoading(false);
      });
    }
  }, [id]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setSaving(true);
    try {
      const payload = {
        ...form,
        cliente_id: Number(form.cliente_id),
        sena_recibida: Number(form.sena_recibida),
        saldo_pendiente: Number(form.saldo_pendiente),
        fecha_entrega: form.fecha_entrega || null,
      };
      if (isEdit) {
        await updateOrden(id, payload);
      } else {
        await createOrden(payload);
      }
      navigate('/ordenes');
    } catch (err) {
      alert('Error al guardar');
    } finally {
      setSaving(false);
    }
  };

  if (loading) return <Loading />;

  return (
    <div>
      <div style={{ marginBottom: 24 }}>
        <h1 style={{ fontSize: 24, fontWeight: 700 }}>{isEdit ? 'Editar Orden de Trabajo' : 'Nueva Orden de Trabajo'}</h1>
      </div>

      <form onSubmit={handleSubmit}>
        <div style={{ display: 'grid', gap: 20, maxWidth: 900 }}>
          <div className="card">
            <h3 className="section-title">Datos del Cliente</h3>
            <div className="form-group">
              <label>Cliente *</label>
              <select className="input" required value={form.cliente_id} onChange={(e) => setForm({ ...form, cliente_id: e.target.value })}>
                <option value="">Seleccionar cliente...</option>
                {clientes.map((c) => <option key={c.id} value={c.id}>{c.nombre}</option>)}
              </select>
            </div>
          </div>

          <div className="card">
            <h3 className="section-title">Especificaciones</h3>
            <div className="form-row">
              <div className="form-group"><label>Material</label><input className="input" value={form.material} onChange={(e) => setForm({ ...form, material: e.target.value })} /></div>
              <div className="form-group"><label>Color / Tipo</label><input className="input" value={form.color_tipo} onChange={(e) => setForm({ ...form, color_tipo: e.target.value })} /></div>
            </div>
            <div className="form-row">
              <div className="form-group"><label>Espesor</label><input className="input" value={form.espesor} onChange={(e) => setForm({ ...form, espesor: e.target.value })} /></div>
              <div className="form-group"><label>Bacha</label><input className="input" value={form.bacha} onChange={(e) => setForm({ ...form, bacha: e.target.value })} /></div>
            </div>
            <div className="form-group"><label>Anafe</label><input className="input" value={form.anafe} onChange={(e) => setForm({ ...form, anafe: e.target.value })} /></div>
          </div>

          <div className="card">
            <h3 className="section-title">Información Comercial</h3>
            <div className="form-row">
              <div className="form-group"><label>Seña recibida ($)</label><input className="input" type="number" step="0.01" value={form.sena_recibida} onChange={(e) => setForm({ ...form, sena_recibida: e.target.value })} /></div>
              <div className="form-group"><label>Saldo pendiente ($)</label><input className="input" type="number" step="0.01" value={form.saldo_pendiente} onChange={(e) => setForm({ ...form, saldo_pendiente: e.target.value })} /></div>
            </div>
            <div className="form-row">
              <div className="form-group"><label>Fecha de entrega</label><input className="input" type="date" value={form.fecha_entrega} onChange={(e) => setForm({ ...form, fecha_entrega: e.target.value })} /></div>
              <div className="form-group"><label>Prioridad</label>
                <select className="input" value={form.prioridad} onChange={(e) => setForm({ ...form, prioridad: e.target.value })}>
                  <option value="Normal">Normal</option>
                  <option value="Urgente">Urgente</option>
                </select>
              </div>
            </div>
          </div>

          <div className="card">
            <h3 className="section-title">Observaciones</h3>
            <div className="form-group">
              <textarea className="input" rows={4} value={form.observaciones} onChange={(e) => setForm({ ...form, observaciones: e.target.value })} />
            </div>
          </div>

          <div style={{ display: 'flex', gap: 12, justifyContent: 'flex-end' }}>
            <button type="button" className="btn btn-outline" onClick={() => navigate('/ordenes')}>Cancelar</button>
            <button type="submit" className="btn btn-primary" disabled={saving}>
              <Save size={16} /> {saving ? 'Guardando...' : (isEdit ? 'Actualizar' : 'Crear Orden')}
            </button>
          </div>
        </div>
      </form>
    </div>
  );
}
